      "path": "src/modules/projects/service.js",
      "content": "const { randomUUID } = require('node:crypto');
const projects = {}; // In-memory storage for simplicity

// Get project by ID
exports.getProjectById = (projectId) => {
  return projects[projectId];
};

// Add new project
exports.addProject = ({ name }) => {
  if (!name) throw new Error('E_BADREQUEST', 'Name is required');
  const id = randomUUID();
  projects[id] = { id, name };
  return { id, name };
};
